const express = require('express');
const bodyParser = require('body-parser');
const { v4: uuidv4 } = require('uuid'); // For generating unique IDs

const app = express();
const port = 3000;

app.use(bodyParser.json());

// In-memory store for level completions.
// In a real application, this would be a persistent database (e.g., MongoDB, PostgreSQL).
const levelCompletions = new Map(); // Maps completionId -> { levelId, score, time, timestamp }

// --- Reward Logic ---
// This function determines what rewards a player gets based on their performance.
// Customize these rules extensively for your specific game.
function calculateRewards(levelId, score, time) {
    const rewards = [];

    // Example reward tiers based on score
    if (score >= 1000) {
        rewards.push({ type: 'coins', amount: 200 });
        rewards.push({ type: 'gems', amount: 3 });
        rewards.push({ type: 'rare_chest', amount: 1 });
    } else if (score >= 750) {
        rewards.push({ type: 'coins', amount: 100 });
        rewards.push({ type: 'gems', amount: 1 });
    } else if (score >= 500) {
        rewards.push({ type: 'coins', amount: 50 });
    }

    // Example time-based bonuses (lower time is generally better)
    if (time <= 30) { // Very fast completion
        rewards.push({ type: 'speed_bonus_item', amount: 1 });
    } else if (time <= 60 && score >= 700) { // Decent speed with good score
        rewards.push({ type: 'quick_finish_coins', amount: 25 });
    }

    // Specific rewards for certain levels (example)
    if (levelId === 'tutorial_level_1' && score > 0) {
        rewards.push({ type: 'first_win_bonus_coins', amount: 10 });
    }

    // Default or participation rewards if no other conditions are met
    if (rewards.length === 0 && score > 0) {
        rewards.push({ type: 'coins', amount: 10 }); // Basic reward for playing
    }

    return rewards;
}

// --- API Endpoints ---

/**
 * @api {post} /complete-level Complete a Level
 * @apiDescription Records the completion of a level by a player.
 *                 This endpoint primarily stores the completion data. Rewards are claimed separately.
 * @apiParam {String} levelId Unique identifier for the level.
 * @apiParam {Number} score The player's score for the completed level.
 * @apiParam {Number} time The time (in seconds) it took the player to complete the level.
 * @apiSuccess {String} message Confirmation message.
 * @apiSuccess {String} completionId A unique ID for this specific level completion.
 * @apiError (400) {String} error Error message if input is invalid.
 */
app.post('/complete-level', (req, res) => {
    const { levelId, score, time } = req.body;

    // Basic input validation
    if (!levelId || typeof score !== 'number' || typeof time !== 'number' || score < 0 || time < 0) {
        return res.status(400).json({ error: 'Invalid input: levelId (string), score (number >= 0), and time (number >= 0) are required.' });
    }

    const completionId = uuidv4(); // Generate a unique ID for this completion event
    const completionData = {
        levelId,
        score,
        time,
        timestamp: new Date().toISOString() // Record when the completion happened
    };

    // Store the completion data in our in-memory map
    levelCompletions.set(completionId, completionData);

    console.log(`Level Completion Recorded: ID=${completionId}, Data=${JSON.stringify(completionData)}`);

    res.status(200).json({
        message: 'Level completion recorded successfully.',
        completionId: completionId // Return the ID so the client can reference it if needed
    });
});

/**
 * @api {post} /claim-rewards Claim Rewards
 * @apiDescription Allows a player to claim rewards for a previously completed level.
 *                 Rewards are calculated based on the client-reported metrics.
 *                 In a production environment, you might verify these metrics against stored
 *                 completion data (if the client sends `completionId`) or other server-side logic
 *                 to prevent cheating.
 * @apiParam {String} levelId Unique identifier for the level for which rewards are being claimed.
 * @apiParam {Number} score The player's score for the level completion.
 * @apiParam {Number} time The time (in seconds) it took the player to complete the level.
 * @apiSuccess {String} message Confirmation message.
 * @apiSuccess {Object[]} rewards An array of awarded items/currencies.
 * @apiSuccess {String} rewards.type The type of reward (e.g., "coins", "gems", "item").
 * @apiSuccess {Number} rewards.amount The quantity of the reward.
 * @apiError (400) {String} error Error message if input is invalid.
 */
app.post('/claim-rewards', (req, res) => {
    const { levelId, score, time } = req.body;

    // Basic input validation
    if (!levelId || typeof score !== 'number' || typeof time !== 'number' || score < 0 || time < 0) {
        return res.status(400).json({ error: 'Invalid input: levelId (string), score (number >= 0), and time (number >= 0) are required for claiming rewards.' });
    }

    // Calculate rewards based on the client-reported metrics
    const awardedRewards = calculateRewards(levelId, score, time);

    console.log(`Rewards Claimed for Level ${levelId} (Score: ${score}, Time: ${time}): ${JSON.stringify(awardedRewards)}`);

    // In a real game, this is where you would:
    // 1. Update the player's inventory/currency in your database.
    // 2. Potentially log the reward transaction for analytics/auditing.
    // For this example, we just return the calculated rewards.

    res.status(200).json({
        message: 'Rewards claimed successfully.',
        rewards: awardedRewards
    });
});

/**
 * @api {get} / Health Check
 * @apiDescription A simple endpoint to check if the API is running.
 * @apiSuccess {String} message A welcome message.
 */
app.get('/', (req, res) => {
    res.status(200).send('Mobile Game API is running!');
});

// Start the server
app.listen(port, () => {
    console.log(`Mobile Game API listening at http://localhost:${port}`);
    console.log('To run this server:');
    console.log('1. Make sure you have Node.js installed.');
    console.log('2. Create a project directory and save this code as, e.g., app.js.');
    console.log('3. Open your terminal in that directory.');
    console.log('4. Run `npm install express body-parser uuid`');
    console.log('5. Run `node app.js`');
    console.log('\n--- Example Usage (using curl) ---');
    console.log('// Complete a level');
    console.log('curl -X POST -H "Content-Type: application/json" -d \'{"levelId": "level_1_easy", "score": 850, "time": 45}\' http://localhost:3000/complete-level');
    console.log('\n// Claim rewards for that completion');
    console.log('curl -X POST -H "Content-Type: application/json" -d \'{"levelId": "level_1_easy", "score": 850, "time": 45}\' http://localhost:3000/claim-rewards');
});